#include <stdio.h>
#include <string.h>
#include <stdlib.h>

char* makeValid(char *s){
    int n = strlen(s);
    int *stack = (int*)malloc(n * sizeof(int));
    int top = -1;
    for(int i=0;i<n;i++){
        if(s[i]=='('){
            stack[++top]=i;
        }else if(s[i]==')'){
            if(top==-1){
                s[i]='#';
            }else{
                top--; // matched
            }
        }
    }
    while(top!=-1){
        s[stack[top--]]='#';
    }
    char *res = (char*)malloc((n+1)*sizeof(char));
    int j=0;
    for(int i=0;i<n;i++) if(s[i]!='#') res[j++]=s[i];
    res[j]='\0';
    if(j==0){
        strcpy(res,"-1");
    }
    free(stack);
    return res;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char buf[100005];
        scanf("%s",buf);
        char *ans = makeValid(buf);
        printf("%s\n",ans);
        free(ans);
    }
    return 0;
}

