#include <bits/stdc++.h>
using namespace std;

string makeValid(string s){
    vector<int> st;
    st.reserve(s.size());
    for(int i=0;i<(int)s.size();++i){
        if(s[i]=='(') st.push_back(i);
        else if(s[i]==')'){
            if(st.empty()) s[i]='#';
            else st.pop_back();
        }
    }
    for(int idx:st) s[idx]='#';
    string res; res.reserve(s.size());
    for(char c:s) if(c!='#') res.push_back(c);
    return res.empty()?"-1":res;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        string s; cin>>s;
        cout<<makeValid(s)<<'\n';
    }
    return 0;
}

