import sys
def make_valid(s):
    stack=[]
    s_list=list(s)
    for i,ch in enumerate(s_list):
        if ch=='(':
            stack.append(i)
        elif ch==')':
            if not stack:
                s_list[i]='#'
            else:
                stack.pop()
    while stack:
        idx=stack.pop()
        s_list[idx]='#'
    res=''.join(c for c in s_list if c!='#')
    return res if res else '-1'

data=sys.stdin.read().splitlines()
if not data:
    sys.exit()
T=int(data[0])
out=[]
for i in range(1,T+1):
    out.append(make_valid(data[i].rstrip('\n')))
print('\n'.join(out))

