const fs = require('fs');
const lines = fs.readFileSync(0,'utf-8').trim().split('\n');
let idx=0;
function makeValid(s){
  const arr = s.split('');
  const stack=[];
  for(let i=0;i<arr.length;i++){
    if(arr[i]==='(') stack.push(i);
    else if(arr[i]===')'){
      if(stack.length===0) arr[i]='#';
      else stack.pop();
    }
  }
  while(stack.length){
    const pos=stack.pop();
    arr[pos]='#';
  }
  const res = arr.filter(ch=>ch!=='#').join('');
  return res.length===0?'-1':res;
}
